  1→//! Persistent storage backend using sled (embedded key-value database).
  2→//!
  3→//! Replaces `MemoryStore` so that Signal Protocol session state survives
  4→//! restarts — users don't need to re-scan the QR code every time.
  5→//!
  6→//! Each account gets its own sled database at `<data_dir>/whatsapp/<account_id>/`.
  7→
  8→use std::{fmt::Write, path::Path, sync::atomic::AtomicI32};
  9→
 10→use {
 11→    async_trait::async_trait,
 12→    serde::{Serialize, de::DeserializeOwned},
 13→    wacore::{
 14→        appstate::{hash::HashState, processor::AppStateMutationMAC},
 15→        store::{
 16→            error::{Result, StoreError, db_err},
 17→            traits::*,
 18→        },
 19→    },
 20→};
 21→
 22→/// Hex-encode bytes without pulling in the `hex` crate.
 23→fn hex_encode(bytes: &[u8]) -> String {
 24→    let mut s = String::with_capacity(bytes.len() * 2);
 25→    for b in bytes {
 26→        let _ = write!(s, "{b:02x}");
 27→    }
 28→    s
 29→}
 30→
 31→/// Persistent store backed by sled, implementing all wacore storage traits.
 32→pub struct SledStore {
 33→    #[allow(dead_code)]
 34→    db: sled::Db,
 35→    identities: sled::Tree,
 36→    sessions: sled::Tree,
 37→    prekeys: sled::Tree,
 38→    signed_prekeys: sled::Tree,
 39→    sender_keys: sled::Tree,
 40→    sync_keys: sled::Tree,
 41→    app_state_versions: sled::Tree,
 42→    mutation_macs: sled::Tree,
 43→    mutation_mac_indexes: sled::Tree,
 44→    device_data: sled::Tree,
 45→    device_id: AtomicI32,
 46→    skdm_recipients: sled::Tree,
 47→    lid_mappings: sled::Tree,
 48→    pn_mappings: sled::Tree,
 49→    device_list_records: sled::Tree,
 50→    sender_key_forget_marks: sled::Tree,
 51→    base_keys: sled::Tree,
 52→}
 53→
 54→fn json_err(e: serde_json::Error) -> StoreError {
 55→    StoreError::Serialization(e.to_string())
 56→}
 57→
 58→fn postcard_err(e: postcard::Error) -> StoreError {
 59→    StoreError::Serialization(e.to_string())
 60→}
 61→
 62→/// Format tag prefixed to every encoded record.
 63→const FORMAT_POSTCARD: u8 = 0x01;
 64→
 65→fn encode_persistent<T: Serialize>(value: &T) -> Result<Vec<u8>> {
 66→    let body = postcard::to_allocvec(value).map_err(postcard_err)?;
 67→    let mut buf = Vec::with_capacity(1 + body.len());
 68→    buf.push(FORMAT_POSTCARD);
 69→    buf.extend_from_slice(&body);
 70→    Ok(buf)
 71→}
 72→
 73→fn decode_persistent<T: DeserializeOwned>(bytes: &[u8]) -> Result<T> {
 74→    if bytes.first() == Some(&FORMAT_POSTCARD) {
 75→        return postcard::from_bytes::<T>(&bytes[1..]).map_err(postcard_err);
 76→    }
 77→    // Legacy: untagged data is JSON (pre-postcard migration).
 78→    serde_json::from_slice(bytes).map_err(json_err)
 79→}
 80→
 81→impl SledStore {
 82→    /// Open or create a sled database at the given path.
 83→    pub fn open(path: impl AsRef<Path>) -> std::result::Result<Self, sled::Error> {
 84→        let db = sled::open(path)?;
 85→
 86→        // Load persisted device_id counter.
 87→        let device_id_tree = db.open_tree("device_id")?;
 88→        let id_val = device_id_tree
 89→            .get(b"counter")?
 90→            .and_then(|v| v.as_ref().try_into().ok())
 91→            .map(i32::from_le_bytes)
 92→            .unwrap_or(0);
 93→
 94→        Ok(Self {
 95→            identities: db.open_tree("identities")?,
 96→            sessions: db.open_tree("sessions")?,
 97→            prekeys: db.open_tree("prekeys")?,
 98→            signed_prekeys: db.open_tree("signed_prekeys")?,
 99→            sender_keys: db.open_tree("sender_keys")?,
100→            sync_keys: db.open_tree("sync_keys")?,
101→            app_state_versions: db.open_tree("app_state_versions")?,
102→            mutation_macs: db.open_tree("mutation_macs")?,
103→            mutation_mac_indexes: db.open_tree("mutation_mac_indexes")?,
104→            device_data: db.open_tree("device_data")?,
105→            device_id: AtomicI32::new(id_val),
106→            skdm_recipients: db.open_tree("skdm_recipients")?,
107→            lid_mappings: db.open_tree("lid_mappings")?,
108→            pn_mappings: db.open_tree("pn_mappings")?,
109→            device_list_records: db.open_tree("device_list_records")?,
110→            sender_key_forget_marks: db.open_tree("sender_key_forget_marks")?,
111→            base_keys: db.open_tree("base_keys")?,
112→            db,
113→        })
114→    }
115→}
116→
117→// ============================================================================
118→// SignalStore
119→// ============================================================================
120→
121→#[async_trait]
122→impl SignalStore for SledStore {
123→    async fn put_identity(&self, address: &str, key: [u8; 32]) -> Result<()> {
124→        self.identities
125→            .insert(address.as_bytes(), &key[..])
126→            .map_err(db_err)?;
127→        Ok(())
128→    }
129→
130→    async fn load_identity(&self, address: &str) -> Result<Option<Vec<u8>>> {
131→        Ok(self
132→            .identities
133→            .get(address.as_bytes())
134→            .map_err(db_err)?
135→            .map(|v| v.to_vec()))
136→    }
137→
138→    async fn delete_identity(&self, address: &str) -> Result<()> {
139→        self.identities.remove(address.as_bytes()).map_err(db_err)?;
140→        Ok(())
141→    }
142→
143→    async fn get_session(&self, address: &str) -> Result<Option<Vec<u8>>> {
144→        Ok(self
145→            .sessions
146→            .get(address.as_bytes())
147→            .map_err(db_err)?
148→            .map(|v| v.to_vec()))
149→    }
150→
151→    async fn put_session(&self, address: &str, session: &[u8]) -> Result<()> {
152→        self.sessions
153→            .insert(address.as_bytes(), session)
154→            .map_err(db_err)?;
155→        Ok(())
156→    }
157→
158→    async fn delete_session(&self, address: &str) -> Result<()> {
159→        self.sessions.remove(address.as_bytes()).map_err(db_err)?;
160→        Ok(())
161→    }
162→
163→    async fn store_prekey(&self, id: u32, record: &[u8], uploaded: bool) -> Result<()> {
164→        // Store as JSON: [record_bytes, uploaded_bool]
165→        let val = serde_json::to_vec(&(record, uploaded)).map_err(json_err)?;
166→        self.prekeys
167→            .insert(id.to_le_bytes(), val.as_slice())
168→            .map_err(db_err)?;
169→        Ok(())
170→    }
171→
172→    async fn load_prekey(&self, id: u32) -> Result<Option<Vec<u8>>> {
173→        match self.prekeys.get(id.to_le_bytes()).map_err(db_err)? {
174→            Some(v) => {
175→                let (record, _uploaded): (Vec<u8>, bool) =
176→                    serde_json::from_slice(&v).map_err(json_err)?;
177→                Ok(Some(record))
178→            },
179→            None => Ok(None),
180→        }
181→    }
182→
183→    async fn remove_prekey(&self, id: u32) -> Result<()> {
184→        self.prekeys.remove(id.to_le_bytes()).map_err(db_err)?;
185→        Ok(())
186→    }
187→
188→    async fn store_signed_prekey(&self, id: u32, record: &[u8]) -> Result<()> {
189→        self.signed_prekeys
190→            .insert(id.to_le_bytes(), record)
191→            .map_err(db_err)?;
192→        Ok(())
193→    }
194→
195→    async fn load_signed_prekey(&self, id: u32) -> Result<Option<Vec<u8>>> {
196→        Ok(self
197→            .signed_prekeys
198→            .get(id.to_le_bytes())
199→            .map_err(db_err)?
200→            .map(|v| v.to_vec()))
201→    }
202→
203→    async fn load_all_signed_prekeys(&self) -> Result<Vec<(u32, Vec<u8>)>> {
204→        let mut result = Vec::new();
205→        for entry in self.signed_prekeys.iter() {
206→            let (k, v) = entry.map_err(db_err)?;
207→            if let Ok(bytes) = k.as_ref().try_into() {
208→                let id = u32::from_le_bytes(bytes);
209→                result.push((id, v.to_vec()));
210→            }
211→        }
212→        Ok(result)
213→    }
214→
215→    async fn remove_signed_prekey(&self, id: u32) -> Result<()> {
