246→// AppSyncStore
247→// ============================================================================
248→
249→#[async_trait]
250→impl AppSyncStore for SledStore {
251→    async fn get_sync_key(&self, key_id: &[u8]) -> Result<Option<AppStateSyncKey>> {
252→        match self.sync_keys.get(key_id).map_err(db_err)? {
253→            Some(v) => Ok(Some(decode_persistent(&v)?)),
254→            None => Ok(None),
255→        }
256→    }
257→
258→    async fn set_sync_key(&self, key_id: &[u8], key: AppStateSyncKey) -> Result<()> {
259→        let val = encode_persistent(&key)?;
260→        self.sync_keys
261→            .insert(key_id, val.as_slice())
262→            .map_err(db_err)?;
263→        Ok(())
264→    }
265→
266→    async fn get_version(&self, name: &str) -> Result<HashState> {
267→        match self
268→            .app_state_versions
269→            .get(name.as_bytes())
270→            .map_err(db_err)?
271→        {
272→            Some(v) => decode_persistent(&v),
273→            None => Ok(HashState::default()),
274→        }
275→    }
276→
277→    async fn set_version(&self, name: &str, state: HashState) -> Result<()> {
278→        let val = encode_persistent(&state)?;
279→        self.app_state_versions
280→            .insert(name.as_bytes(), val.as_slice())
281→            .map_err(db_err)?;
282→        Ok(())
283→    }
284→
285→    async fn put_mutation_macs(
286→        &self,
287→        name: &str,
288→        version: u64,
289→        mutations: &[AppStateMutationMAC],
290→    ) -> Result<()> {
291→        let version_key = format!("{name}:{version}");
292→        let mut indexes = Vec::new();
293→        for mac in mutations {
294→            let mac_key = format!("{name}:{version}:{}", hex_encode(&mac.index_mac));
295→            self.mutation_macs
296→                .insert(mac_key.as_bytes(), mac.value_mac.as_slice())
297→                .map_err(db_err)?;
298→            indexes.push(mac.index_mac.clone());
299→        }
300→        let idx_val = encode_persistent(&indexes)?;
301→        self.mutation_mac_indexes
302→            .insert(version_key.as_bytes(), idx_val.as_slice())
303→            .map_err(db_err)?;
304→        Ok(())
305→    }
306→
307→    async fn get_mutation_mac(&self, name: &str, index_mac: &[u8]) -> Result<Option<Vec<u8>>> {
308→        let prefix = format!("{name}:");
309→        let hex_mac = hex_encode(index_mac);
310→        for entry in self.mutation_mac_indexes.iter() {
311→            let (k, _) = entry.map_err(db_err)?;
312→            let key_str = String::from_utf8_lossy(&k);
313→            if key_str.starts_with(&prefix) {
314→                let mac_key = format!("{key_str}:{hex_mac}");
315→                if let Some(value_mac) =
316→                    self.mutation_macs.get(mac_key.as_bytes()).map_err(db_err)?
317→                {
318→                    return Ok(Some(value_mac.to_vec()));
319→                }
320→            }
321→        }
322→        Ok(None)
323→    }
324→
325→    async fn delete_mutation_macs(&self, name: &str, index_macs: &[Vec<u8>]) -> Result<()> {
326→        for index_mac in index_macs {
327→            let hex_mac = hex_encode(index_mac);
328→            let prefix = format!("{name}:");
329→            let mut keys_to_remove = Vec::new();
330→            for entry in self.mutation_macs.iter() {
331→                let (k, _) = entry.map_err(db_err)?;
332→                let key_str = String::from_utf8_lossy(&k);
333→                if key_str.starts_with(&prefix) && key_str.ends_with(&hex_mac) {
334→                    keys_to_remove.push(k);
335→                }
336→            }
337→            for key in keys_to_remove {
338→                self.mutation_macs.remove(key).map_err(db_err)?;
339→            }
340→        }
341→        Ok(())
342→    }
343→}
