428→    ) -> Result<bool> {
429→        let key = format!("{address}:{message_id}");
430→        Ok(self
431→            .base_keys
432→            .get(key.as_bytes())
433→            .map_err(db_err)?
434→            .is_some_and(|v| v.as_ref() == current_base_key))
435→    }
