149→// ============================================================================
150→// AppSyncStore
151→// ============================================================================
152→
153→#[async_trait]
154→impl AppSyncStore for MemoryStore {
155→    async fn get_sync_key(&self, key_id: &[u8]) -> Result<Option<AppStateSyncKey>> {
156→        Ok(self.sync_keys.get(key_id).map(|v| v.value().clone()))
157→    }
158→
159→    async fn set_sync_key(&self, key_id: &[u8], key: AppStateSyncKey) -> Result<()> {
160→        self.sync_keys.insert(key_id.to_vec(), key);
161→        Ok(())
162→    }
163→
164→    async fn get_version(&self, name: &str) -> Result<HashState> {
165→        Ok(self
166→            .app_state_versions
167→            .get(name)
168→            .map(|v| v.value().clone())
169→            .unwrap_or_default())
170→    }
171→
172→    async fn set_version(&self, name: &str, state: HashState) -> Result<()> {
173→        self.app_state_versions.insert(name.to_string(), state);
174→        Ok(())
175→    }
176→
177→    async fn put_mutation_macs(
178→        &self,
179→        name: &str,
180→        version: u64,
181→        mutations: &[AppStateMutationMAC],
182→    ) -> Result<()> {
183→        let version_key = format!("{name}:{version}");
184→        let mut indexes = Vec::new();
185→        for mac in mutations {
186→            let mac_key = format!("{name}:{version}:{}", hex_encode(&mac.index_mac));
187→            self.mutation_macs.insert(mac_key, mac.value_mac.clone());
188→            indexes.push(mac.index_mac.clone());
189→        }
190→        self.mutation_mac_indexes.insert(version_key, indexes);
191→        Ok(())
192→    }
193→
194→    async fn get_mutation_mac(&self, name: &str, index_mac: &[u8]) -> Result<Option<Vec<u8>>> {
195→        // Search across all versions for this name + index_mac combo.
196→        for entry in self.mutation_mac_indexes.iter() {
197→            if entry.key().starts_with(&format!("{name}:")) {
198→                let version_key = entry.key();
199→                let mac_key = format!("{version_key}:{}", hex_encode(index_mac));
200→                if let Some(value_mac) = self.mutation_macs.get(&mac_key) {
201→                    return Ok(Some(value_mac.value().clone()));
202→                }
203→            }
204→        }
205→        Ok(None)
206→    }
207→
208→    async fn delete_mutation_macs(&self, name: &str, index_macs: &[Vec<u8>]) -> Result<()> {
209→        for index_mac in index_macs {
210→            let hex_mac = hex_encode(index_mac);
211→            // Remove from all versions.
212→            let keys_to_remove: Vec<String> = self
213→                .mutation_macs
214→                .iter()
215→                .filter(|e| e.key().starts_with(&format!("{name}:")) && e.key().ends_with(&hex_mac))
216→                .map(|e| e.key().clone())
217→                .collect();
218→            for key in keys_to_remove {
219→                self.mutation_macs.remove(&key);
220→            }
221→        }
222→        Ok(())
223→    }
224→}
