226→// ============================================================================
227→// ProtocolStore
228→// ============================================================================
229→
230→#[async_trait]
231→impl ProtocolStore for MemoryStore {
232→    async fn get_skdm_recipients(&self, group_jid: &str) -> Result<Vec<String>> {
233→        Ok(self
234→            .skdm_recipients
235→            .get(group_jid)
236→            .map(|v| v.value().clone())
237→            .unwrap_or_default())
238→    }
239→
240→    async fn add_skdm_recipients(&self, group_jid: &str, device_jids: &[String]) -> Result<()> {
241→        self.skdm_recipients
242→            .entry(group_jid.to_string())
243→            .or_default()
244→            .extend(device_jids.iter().cloned());
245→        Ok(())
246→    }
247→
248→    async fn clear_skdm_recipients(&self, group_jid: &str) -> Result<()> {
249→        self.skdm_recipients.remove(group_jid);
250→        Ok(())
251→    }
252→
253→    async fn get_lid_mapping(&self, lid: &str) -> Result<Option<LidPnMappingEntry>> {
254→        Ok(self.lid_mappings.get(lid).map(|v| v.value().clone()))
255→    }
256→
257→    async fn get_pn_mapping(&self, phone: &str) -> Result<Option<LidPnMappingEntry>> {
258→        if let Some(lid) = self.pn_mappings.get(phone) {
259→            return Ok(self
260→                .lid_mappings
261→                .get(lid.value())
262→                .map(|v| v.value().clone()));
263→        }
264→        Ok(None)
265→    }
266→
267→    async fn put_lid_mapping(&self, entry: &LidPnMappingEntry) -> Result<()> {
268→        self.pn_mappings
269→            .insert(entry.phone_number.clone(), entry.lid.clone());
270→        self.lid_mappings.insert(entry.lid.clone(), entry.clone());
271→        Ok(())
272→    }
273→
274→    async fn get_all_lid_mappings(&self) -> Result<Vec<LidPnMappingEntry>> {
275→        Ok(self
276→            .lid_mappings
277→            .iter()
278→            .map(|e| e.value().clone())
279→            .collect())
280→    }
281→
282→    async fn save_base_key(&self, address: &str, message_id: &str, base_key: &[u8]) -> Result<()> {
283→        let key = format!("{address}:{message_id}");
284→        self.base_keys.insert(key, base_key.to_vec());
285→        Ok(())
286→    }
287→
288→    async fn has_same_base_key(
289→        &self,
290→        address: &str,
291→        message_id: &str,
292→        current_base_key: &[u8],
293→    ) -> Result<bool> {
294→        let key = format!("{address}:{message_id}");
295→        Ok(self
296→            .base_keys
297→            .get(&key)
298→            .is_some_and(|v| v.value() == current_base_key))
299→    }
300→
301→    async fn delete_base_key(&self, address: &str, message_id: &str) -> Result<()> {
302→        let key = format!("{address}:{message_id}");
303→        self.base_keys.remove(&key);
304→        Ok(())
305→    }
306→
307→    async fn update_device_list(&self, record: DeviceListRecord) -> Result<()> {
308→        self.device_list_records.insert(record.user.clone(), record);
309→        Ok(())
310→    }
311→
312→    async fn get_devices(&self, user: &str) -> Result<Option<DeviceListRecord>> {
313→        Ok(self
314→            .device_list_records
315→            .get(user)
316→            .map(|v| v.value().clone()))
317→    }
318→
319→    async fn mark_forget_sender_key(&self, group_jid: &str, participant: &str) -> Result<()> {
320→        let key = format!("{group_jid}:{participant}");
321→        self.sender_key_forget_marks.insert(key, true);
322→        Ok(())
323→    }
324→
325→    async fn consume_forget_marks(&self, group_jid: &str) -> Result<Vec<String>> {
326→        let prefix = format!("{group_jid}:");
327→        let keys: Vec<String> = self
328→            .sender_key_forget_marks
329→            .iter()
330→            .filter(|e| e.key().starts_with(&prefix))
331→            .map(|e| e.key().clone())
332→            .collect();
333→
334→        let mut participants = Vec::new();
335→        for key in keys {
336→            self.sender_key_forget_marks.remove(&key);
337→            if let Some(participant) = key.strip_prefix(&prefix) {
338→                participants.push(participant.to_string());
339→            }
340→        }
341→        Ok(participants)
342→    }
343→}
