323→            handle_otp_flow(
324→                accounts,
325→                &state.account_id,
326→                &peer_id,
327→                Some(&username),
328→                sender_name.as_deref(),
329→                text,
330→                chat_jid,
331→                state,
332→            )
333→            .await;
334→        }
335→        return;
336→    }
337→
338→    // Check for slash commands.
339→    if let Some(cmd) = text.strip_prefix('/') {
340→        let reply_to = ChannelReplyTarget {
341→            channel_type: ChannelType::Whatsapp,
342→            account_id: state.account_id.clone(),
343→            chat_id: chat_id.clone(),
344→            message_id: Some(info.id.to_string()),
345→            thread_id: None,
346→        };
347→        if let Some(ref sink) = state.event_sink {
348→            match sink.dispatch_command(cmd, reply_to, Some(&peer_id)).await {
349→                Ok(response) => {
