 458→/// Handle an inbound photo/image message: download, optimize, dispatch with attachment.
 459→#[allow(clippy::too_many_arguments)]
 460→async fn handle_photo(
 461→    msg: &wa::Message,
 462→    client: &Client,
 463→    account_id: &str,
 464→    reply_to: ChannelReplyTarget,
 465→    meta: ChannelMessageMeta,
 466→    _chat_jid: &Jid,
 467→    state: &AccountState,
 468→) {
 469→    let Some(ref img) = msg.image_message else {
 470→        return;
 471→    };
 472→    let caption = img.caption.as_deref().unwrap_or("").to_string();
 473→    let mime = img.mimetype.as_deref().unwrap_or("image/jpeg").to_string();
 474→
 475→    match client.download(img.as_ref()).await {
 476→        Ok(image_data) => {
 477→            debug!(account_id, size = image_data.len(), %mime, "downloaded WhatsApp image");
 478→
 479→            let (final_data, media_type) = match moltis_media::image_ops::optimize_for_llm(
 480→                &image_data,
 481→                None,
 482→            ) {
 483→                Ok(optimized) => {
 484→                    if optimized.was_resized {
 485→                        info!(
 486→                            account_id,
 487→                            original_size = image_data.len(),
 488→                            final_size = optimized.data.len(),
 489→                            original_dims = %format!("{}x{}", optimized.original_width, optimized.original_height),
 490→                            final_dims = %format!("{}x{}", optimized.final_width, optimized.final_height),
 491→                            "resized image for LLM"
 492→                        );
 493→                    }
 494→                    (optimized.data, optimized.media_type)
 495→                },
 496→                Err(e) => {
 497→                    warn!(account_id, error = %e, "failed to optimize image, using original");
 498→                    (image_data, mime)
 499→                },
 500→            };
 501→
 502→            let attachment = ChannelAttachment {
 503→                media_type,
 504→                data: final_data,
 505→            };
 506→            if let Some(ref sink) = state.event_sink {
 507→                sink.dispatch_to_chat_with_attachments(&caption, vec![attachment], reply_to, meta)
 508→                    .await;
 509→            }
 510→        },
 511→        Err(e) => {
 512→            warn!(account_id, error = %e, "failed to download WhatsApp image");
 513→            let fallback = if caption.is_empty() {
 514→                "[Photo - download failed]".to_string()
 515→            } else {
 516→                caption
 517→            };
 518→            if let Some(ref sink) = state.event_sink {
 519→                sink.dispatch_to_chat(&fallback, reply_to, meta).await;
 520→            }
 521→        },
 522→    }
 523→}
