 751→fn capitalize(s: &str) -> String {
 752→    let mut chars = s.chars();
 753→    match chars.next() {
 754→        None => String::new(),
 755→        Some(c) => c.to_uppercase().to_string() + chars.as_str(),
 756→    }
 757→}
