 813→fn should_ignore_inbound_chat(source: &wacore::types::message::MessageSource) -> bool {
 814→    source.chat.is_status_broadcast() || source.is_incoming_broadcast()
 815→}
 816→
 817→fn is_benign_self_chat_protocol_message(msg: &wa::Message) -> bool {
 818→    msg.sender_key_distribution_message.is_some()
 819→        || msg.protocol_message.is_some()
 820→        || msg.reaction_message.is_some()
 821→        || msg.edited_message.is_some()
 822→        || msg.event_message.is_some()
 823→}
 824→
 825→/// List which `Option` fields on `wa::Message` are `Some`, giving operators a
 826→/// concrete clue about the unhandled message type (e.g. "sticker_message, reaction_message").
 827→///
 828→/// Only checks fields that are NOT already handled by `classify_message` to avoid
 829→/// misleading output — if a field appears here it genuinely was not dispatched.
 830→fn describe_message_fields(msg: &wa::Message) -> String {
 831→    let mut present = Vec::new();
 832→    macro_rules! check {
 833→        ($($field:ident),+ $(,)?) => {
 834→            $(if msg.$field.is_some() { present.push(stringify!($field)); })+
 835→        };
 836→    }
 837→    // Omit fields already handled by classify_message:
 838→    //   conversation, extended_text_message, image_message, audio_message,
 839→    //   video_message, document_message, location_message, live_location_message
 840→    check!(
 841→        sender_key_distribution_message,
 842→        contact_message,
 843→        call,
 844→        protocol_message,
 845→        contacts_array_message,
 846→        sticker_message,
 847→        reaction_message,
 848→        poll_creation_message,
 849→        poll_update_message,
 850→        interactive_message,
 851→        edited_message,
 852→        event_message,
 853→    );
 854→    if present.is_empty() {
 855→        "none".to_owned()
 856→    } else {
 857→        present.join(", ")
 858→    }
 859→}
 860→
 861→/// Classify the inbound message kind based on its content.
 862→///
 863→/// Media types take priority over text — an image with a caption is still `Photo`,
 864→/// not `Text`. This ensures the media handler runs and can include the caption
 865→/// alongside the attachment.
 866→fn classify_message(msg: &wa::Message, text: &str) -> ChannelMessageKind {
 867→    if msg.image_message.is_some() {
 868→        ChannelMessageKind::Photo
 869→    } else if msg.audio_message.is_some() {
 870→        if msg
 871→            .audio_message
 872→            .as_ref()
 873→            .is_some_and(|a| a.ptt.unwrap_or(false))
 874→        {
 875→            ChannelMessageKind::Voice
 876→        } else {
 877→            ChannelMessageKind::Audio
 878→        }
 879→    } else if msg.video_message.is_some() {
 880→        ChannelMessageKind::Video
 881→    } else if msg.document_message.is_some() {
 882→        ChannelMessageKind::Document
 883→    } else if msg.location_message.is_some() || msg.live_location_message.is_some() {
 884→        ChannelMessageKind::Location
 885→    } else if !text.is_empty() {
 886→        ChannelMessageKind::Text
 887→    } else {
 888→        ChannelMessageKind::Other
 889→    }
 890→}
