use std::sync::Arc;

use {
    tokio_util::sync::CancellationToken,
    tracing::{info, warn},
};

use moltis_channels::{ChannelEventSink, message_log::MessageLog};

use crate::{
    config::WhatsAppAccountConfig,
    handlers,
    state::{AccountState, AccountStateMap, ShutdownState},
};

/// Start a WhatsApp connection for the given account.
///
/// Builds the `Bot` with a persistent sled store, registers the event handler,
/// and spawns the event loop as a background tokio task. Session state persists
/// across restarts so the user does not need to re-scan the QR code.
pub async fn start_connection(
    account_id: String,
    config: WhatsAppAccountConfig,
    accounts: AccountStateMap,
    data_dir: std::path::PathBuf,
    message_log: Option<Arc<dyn MessageLog>>,
    event_sink: Option<Arc<dyn ChannelEventSink>>,
) -> crate::Result<()> {
    // Use persistent sled store at <data_dir>/whatsapp/<account_id>/.
    let store_path = config
        .store_path
        .clone()
        .unwrap_or_else(|| data_dir.join("whatsapp").join(&account_id));

    info!(account_id = %account_id, path = %store_path.display(), "opening sled WhatsApp store");

    let backend = Arc::new(
        crate::sled_store::SledStore::open(&store_path).map_err(|e| crate::Error::Store {
            message: format!("failed to open sled store at {}: {e}", store_path.display()),
        })?,
    );

    let cancel = CancellationToken::new();
    let cancel_clone = cancel.clone();
    let shutdown = Arc::new(ShutdownState::new());
    let shutdown_clone = Arc::clone(&shutdown);

    // Build the bot.
    let account_id_clone = account_id.clone();
    let event_sink_clone = event_sink.clone();
    let message_log_clone = message_log.clone();

    // We need to create a temporary accounts ref for the state that will be
    // populated after bot.build().
    let state_ref: Arc<tokio::sync::OnceCell<Arc<AccountState>>> =
        Arc::new(tokio::sync::OnceCell::new());
    let state_ref_handler = Arc::clone(&state_ref);
    let accounts_handler = Arc::clone(&accounts);

    let mut bot = whatsapp_rust::bot::Bot::builder()
        .with_backend(backend)
        .with_transport_factory(
            whatsapp_rust_tokio_transport::TokioWebSocketTransportFactory::new(),
        )
        .with_http_client(whatsapp_rust_ureq_http_client::UreqHttpClient::new())
        .on_event(move |event, client| {
            let state_ref = Arc::clone(&state_ref_handler);
            let accounts = Arc::clone(&accounts_handler);
            async move {
                if let Some(state) = state_ref.get() {
                    handlers::handle_event(event, client, Arc::clone(state), accounts).await;
                }
            }
        })
        .build()
        .await
        .map_err(|e| crate::Error::Whatsapp {
            message: e.to_string(),
        })?;

    let client = bot.client();

    // Create account state.
    let otp_cooldown = config.otp_cooldown_secs;
    let account_state = Arc::new(AccountState {
        client: Arc::clone(&client),
        account_id: account_id_clone.clone(),
        config,
        cancel: cancel_clone,
        shutdown: Arc::clone(&shutdown),
        message_log: message_log_clone,
        event_sink: event_sink_clone,
        latest_qr: std::sync::RwLock::new(None),
        connected: std::sync::atomic::AtomicBool::new(false),
        otp: std::sync::Mutex::new(crate::otp::OtpState::new(otp_cooldown)),
        recent_sent_ids: std::sync::Mutex::new(std::collections::VecDeque::new()),
    });

    // Populate the OnceCell so the event handler can access state.
    let _ = state_ref.set(Arc::clone(&account_state));

    // Insert into the shared map.
    {
        let mut map = accounts.write().unwrap_or_else(|e| e.into_inner());
        map.insert(account_id.clone(), AccountState {
            client: Arc::clone(&client),
            account_id: account_id.clone(),
            config: account_state.config.clone(),
            cancel: cancel.clone(),
            shutdown: Arc::clone(&shutdown),
            message_log: account_state.message_log.clone(),
            event_sink: account_state.event_sink.clone(),
            latest_qr: std::sync::RwLock::new(None),
            connected: std::sync::atomic::AtomicBool::new(false),
            otp: std::sync::Mutex::new(crate::otp::OtpState::new(otp_cooldown)),
            recent_sent_ids: std::sync::Mutex::new(std::collections::VecDeque::new()),
        });
    }

    // Spawn the event loop.
    let account_id_task = account_id.clone();
    tokio::spawn(async move {
        tokio::select! {
            result = bot.run() => {
                match result {
                    Ok(handle) => {
                        tokio::pin!(handle);
                        tokio::select! {
                            _ = &mut handle => {
                                info!(account_id = %account_id_task, "WhatsApp bot task completed");
                            },
                            _ = cancel.cancelled() => {
                                info!(account_id = %account_id_task, "WhatsApp account cancelled, aborting bot task");
                                handle.abort();
                                // Wait for the task to finish after abort so the
                                // sled store is fully released before we signal done.
                                let _ = handle.await;
                            },
                        }
                    },
                    Err(e) => {
                        warn!(account_id = %account_id_task, error = %e, "WhatsApp bot failed to start");
                    },
                }
            },
            _ = cancel.cancelled() => {
                info!(account_id = %account_id_task, "WhatsApp account cancelled before start");
            },
        }
        shutdown_clone.mark_done();
    });

    Ok(())
}

//! Persistent storage backend using sled (embedded key-value database).
//!
//! Replaces `MemoryStore` so that Signal Protocol session state survives
//! restarts — users don't need to re-scan the QR code every time.
//!
//! Each account gets its own sled database at `<data_dir>/whatsapp/<account_id>/`.

use std::{fmt::Write, path::Path, sync::atomic::AtomicI32};

use {
    async_trait::async_trait,
    serde::{Serialize, de::DeserializeOwned},
    wacore::{
        appstate::{hash::HashState, processor::AppStateMutationMAC},
        store::{
            error::{Result, StoreError, db_err},
            traits::*,
        },
    },
};

/// Hex-encode bytes without pulling in the `hex` crate.
fn hex_encode(bytes: &[u8]) -> String {
    let mut s = String::with_capacity(bytes.len() * 2);
    for b in bytes {
        let _ = write!(s, "{b:02x}");
    }
    s
}

/// Persistent store backed by sled, implementing all wacore storage traits.
pub struct SledStore {
    #[allow(dead_code)]
    db: sled::Db,
    identities: sled::Tree,
    sessions: sled::Tree,
    prekeys: sled::Tree,
    signed_prekeys: sled::Tree,
    sender_keys: sled::Tree,
    sync_keys: sled::Tree,
    app_state_versions: sled::Tree,
    mutation_macs: sled::Tree,
    mutation_mac_indexes: sled::Tree,
    device_data: sled::Tree,
    device_id: AtomicI32,
    skdm_recipients: sled::Tree,
    lid_mappings: sled::Tree,
    pn_mappings: sled::Tree,
    device_list_records: sled::Tree,
    sender_key_forget_marks: sled::Tree,
    base_keys: sled::Tree,
}

fn json_err(e: serde_json::Error) -> StoreError {
    StoreError::Serialization(e.to_string())
}

fn postcard_err(e: postcard::Error) -> StoreError {
    StoreError::Serialization(e.to_string())
}

/// Format tag prefixed to every encoded record.
const FORMAT_POSTCARD: u8 = 0x01;

fn encode_persistent<T: Serialize>(value: &T) -> Result<Vec<u8>> {
    let body = postcard::to_allocvec(value).map_err(postcard_err)?;
    let mut buf = Vec::with_capacity(1 + body.len());
    buf.push(FORMAT_POSTCARD);
    buf.extend_from_slice(&body);
    Ok(buf)
}

fn decode_persistent<T: DeserializeOwned>(bytes: &[u8]) -> Result<T> {
    if bytes.first() == Some(&FORMAT_POSTCARD) {
        return postcard::from_bytes::<T>(&bytes[1..]).map_err(postcard_err);
    }
    // Legacy: untagged data is JSON (pre-postcard migration).
    serde_json::from_slice(bytes).map_err(json_err)
}

impl SledStore {
    /// Open or create a sled database at the given path.
    pub fn open(path: impl AsRef<Path>) -> std::result::Result<Self, sled::Error> {
        let db = sled::open(path)?;

        // Load persisted device_id counter.
        let device_id_tree = db.open_tree("device_id")?;
        let id_val = device_id_tree
            .get(b"counter")?
            .and_then(|v| v.as_ref().try_into().ok())
            .map(i32::from_le_bytes)
            .unwrap_or(0);

        Ok(Self {
            identities: db.open_tree("identities")?,
            sessions: db.open_tree("sessions")?,
            prekeys: db.open_tree("prekeys")?,
            signed_prekeys: db.open_tree("signed_prekeys")?,
            sender_keys: db.open_tree("sender_keys")?,
            sync_keys: db.open_tree("sync_keys")?,
            app_state_versions: db.open_tree("app_state_versions")?,
            mutation_macs: db.open_tree("mutation_macs")?,
            mutation_mac_indexes: db.open_tree("mutation_mac_indexes")?,
            device_data: db.open_tree("device_data")?,
            device_id: AtomicI32::new(id_val),
            skdm_recipients: db.open_tree("skdm_recipients")?,
            lid_mappings: db.open_tree("lid_mappings")?,
            pn_mappings: db.open_tree("pn_mappings")?,
            device_list_records: db.open_tree("device_list_records")?,
            sender_key_forget_marks: db.open_tree("sender_key_forget_marks")?,
            base_keys: db.open_tree("base_keys")?,
            db,
        })
    }
}

