    }

    #[tokio::test]
    async fn app_state_persistence_survives_reopen() {
        let dir = tempfile::tempdir().unwrap();

        {
            let store = SledStore::open(dir.path()).unwrap();
            let key = AppStateSyncKey {
                key_data: vec![10, 20, 30],
                fingerprint: vec![40, 50],
                timestamp: 98765,
