    #[tokio::test]
    async fn persistence_survives_reopen() {
        let dir = tempfile::tempdir().unwrap();

        // Write some data.
        {
            let store = SledStore::open(dir.path()).unwrap();
            store
                .put_identity("test@s.whatsapp.net", [1u8; 32])
